import type React from "react";

import { cva, type VariantProps } from "class-variance-authority";

import { Card, CardContent, CardHeader, CardTitle } from "../card/Card";
import { MetricTile } from "../metric-tile/MetricTile";
import { StatusIndicator } from "../status-indicator/StatusIndicator";
import { cn } from "../utils/cn";

const metricCardBorderVariants = cva("border-l-4", {
  variants: {
    state: {
      runtime: "border-l-load-state-runtime",
      idle: "border-l-load-state-idle",
      offline: "border-l-load-state-offline",
      planned: "border-l-load-state-planned",
      nodata: "border-l-load-state-nodata",
    },
  },
  defaultVariants: {
    state: "nodata",
  },
});

interface MetricCardOwnProps {
  /** Card title displayed in the header. */
  title: string;
  /** Optional subtitle displayed below the title. */
  subtitle?: string;
  /** Load state controlling the left border color and status dot. */
  state?: "runtime" | "idle" | "offline" | "planned" | "nodata";
  /** Array of metrics to display in a grid of MetricTile components. */
  metrics?: Array<{ label: string; value?: string | number; unit?: string }>;
  /** Click handler. When provided, the card gets hover effects. */
  onClick?: () => void;
  /** Additional content rendered below the metrics grid. */
  children?: React.ReactNode;
}

type MetricCardProps = Omit<React.ComponentProps<"div">, "onClick"> &
  MetricCardOwnProps;

/**
 * A card composing Card, MetricTile, and StatusIndicator to display
 * a device or entity with its current load state and key metrics.
 *
 * The left border is colored by load state, the header shows a title
 * with a status dot, and the body contains a responsive grid of metric tiles.
 */
function MetricCard({
  className,
  title,
  subtitle,
  state = "nodata",
  metrics,
  onClick,
  children,
  ...props
}: MetricCardProps) {
  const isClickable = typeof onClick === "function";
  const gridCols =
    metrics && metrics.length > 0
      ? metrics.length <= 2
        ? "grid-cols-2"
        : "grid-cols-3"
      : "";

  return (
    <Card
      data-slot="metric-card"
      className={cn(
        metricCardBorderVariants({ state }),
        isClickable &&
          "cursor-pointer shadow-sm transition-shadow hover:shadow-md",
        className,
      )}
      onClick={onClick}
      role={isClickable ? "button" : undefined}
      tabIndex={isClickable ? 0 : undefined}
      onKeyDown={
        isClickable
          ? (e: React.KeyboardEvent) => {
              if (e.key === "Enter" || e.key === " ") {
                e.preventDefault();
                onClick?.();
              }
            }
          : undefined
      }
      {...props}
    >
      <CardHeader className="flex flex-row items-center gap-2 pb-2">
        <StatusIndicator state={state} variant="dot" size="sm" />
        <div className="flex flex-col gap-0.5">
          <CardTitle className="text-sm">{title}</CardTitle>
          {subtitle && (
            <p
              data-slot="metric-card-subtitle"
              className="text-xs text-muted-foreground"
            >
              {subtitle}
            </p>
          )}
        </div>
      </CardHeader>
      {metrics && metrics.length > 0 && (
        <CardContent className="pb-3">
          <div
            data-slot="metric-card-grid"
            className={cn("grid gap-2", gridCols)}
          >
            {metrics.map((metric) => (
              <MetricTile
                key={metric.label}
                label={metric.label}
                value={metric.value}
                unit={metric.unit}
                size="sm"
              />
            ))}
          </div>
        </CardContent>
      )}
      {children && (
        <CardContent data-slot="metric-card-extra" className="pt-0">
          {children}
        </CardContent>
      )}
    </Card>
  );
}

export { MetricCard, metricCardBorderVariants };
export type { MetricCardProps };
